private function setResultPackageMaps(array $resultPackages): void
    {
        $packageSort = static function (PackageInterface $a, PackageInterface $b): int {
            // sort alias packages by the same name behind their non alias version
            if ($a->getName() === $b->getName()) {
                if ($a instanceof AliasPackage !== $b instanceof AliasPackage) {
                    return $a instanceof AliasPackage ? -1 : 1;
                }

                // if names are the same, compare version, e.g. to sort aliases reliably, actual order does not matter
                return strcmp($b->getVersion(), $a->getVersion());
            }

            return strcmp($b->getName(), $a->getName());
        };

        $this->resultPackageMap = [];
        foreach ($resultPackages as $package) {
            $this->resultPackageMap[spl_object_hash($package)] = $package;
            foreach ($package->getNames() as $name) {
                $this->resultPackagesByName[$name][] = $package;
            }
        }

        uasort($this->resultPackageMap, $packageSort);
        foreach ($this->resultPackagesByName as $name => $packages) {
            uasort($this->resultPackagesByName[$name], $packageSort);
        }
    }

private function applyCurlOptions($handle, array $conf): void
    {
        foreach ($conf as $option => $value) {
            if (!\is_int($option)) {
                throw new \InvalidArgumentException(\sprintf(
                    'Invalid cURL option %s.',
                    self::formatCurlOption($option)
                ));
            }

            try {
                $success = curl_setopt($handle, $option, $value);
            } catch (\Throwable $e) {
                throw new \InvalidArgumentException(
                    \sprintf(
                        'Unable to set cURL option %s: %s',
                        self::formatCurlOption($option),
                        $e->getMessage()
                    ),
                    0,
                    $e
                );
            }

            if (!$success) {
                throw new \InvalidArgumentException(\sprintf(
                    'Unable to set cURL option %s.',
                    self::formatCurlOption($option)
                ));
            }
        }
    }

private function prepareDefaults(array $options): array
    {
        $defaults = $this->config;

        if (!empty($defaults['headers'])) {
            // Default headers are only added if they are not present.
            $defaults['_conditional'] = $defaults['headers'];
            unset($defaults['headers']);
        }

        // Special handling for headers is required as they are added as
        // conditional headers and as headers passed to a request ctor.
        if (\array_key_exists('headers', $options)) {
            // Allows default headers to be unset.
            if ($options['headers'] === null) {
                $defaults['_conditional'] = [];
                unset($options['headers']);
            } elseif (!\is_array($options['headers'])) {
                throw new InvalidArgumentException('headers must be an array');
            }
        }

        // Shallow merge defaults underneath options.
        $result = $options + $defaults;

        // Remove null values.
        foreach ($result as $k => $v) {
            if ($v === null) {
                unset($result[$k]);
            }
        }

        self::warnAboutInvalidRequestOptionTypes($result);

        return $result;
    }

private function addExpectHeader(RequestInterface $request, array $options, array &$modify): void
    {
        // Determine if the Expect header should be used
        if ($request->hasHeader('Expect')) {
            return;
        }

        $expect = $options['expect'] ?? null;

        // Return if disabled or using HTTP/1.0
        if ($expect === false || $request->getProtocolVersion() === '1.0') {
            return;
        }

        // The expect header is unconditionally enabled
        if ($expect === true) {
            $modify['set_headers']['Expect'] = '100-Continue';

            return;
        }

        // By default, send the expect header when the payload is > 1mb
        if ($expect === null) {
            $expect = 1048576;
        }

        // Always add if the body cannot be rewound, the size cannot be
        // determined, or the size is greater than the cutoff threshold
        $body = $request->getBody();
        $size = $body->getSize();

        if ($size === null || $size >= (int) $expect || !$body->isSeekable()) {
            $modify['set_headers']['Expect'] = '100-Continue';
        }
    }

protected function resolveName(Name $name, int $type): Name {
    if (!$this->replaceNodes) {
        $resolvedName = $this->nameContext->getResolvedName($name, $type);
        if (null !== $resolvedName) {
            $name->setAttribute('resolvedName', $resolvedName);
        } else {
            $name->setAttribute('namespacedName', FullyQualified::concat(
                $this->nameContext->getNamespace(), $name, $name->getAttributes()));
        }
        return $name;
    }

    if ($this->preserveOriginalNames) {
        // Save the original name
        $originalName = $name;
        $name = clone $originalName;
        $name->setAttribute('originalName', $originalName);
    }

    $resolvedName = $this->nameContext->getResolvedName($name, $type);
    if (null !== $resolvedName) {
        return $resolvedName;
    }

    // unqualified names inside a namespace cannot be resolved at compile-time
    // add the namespaced version of the name as an attribute
    $name->setAttribute('namespacedName', FullyQualified::concat(
        $this->nameContext->getNamespace(), $name, $name->getAttributes()));
    return $name;
}

private static function filterAndSortMethods(ReflectionClass $class, ?int $filter, bool $sortHighestToLowest): array
    {
        $methodsByClass = [];

        foreach ($class->getMethods($filter) as $method) {
            $declaringClassName = $method->getDeclaringClass()->getName();

            if ($declaringClassName === TestCase::class) {
                continue;
            }

            if ($declaringClassName === Assert::class) {
                continue;
            }

            if (!isset($methodsByClass[$declaringClassName])) {
                $methodsByClass[$declaringClassName] = [];
            }

            $methodsByClass[$declaringClassName][] = $method;
        }

        if ($sortHighestToLowest) {
            $methodsByClass = array_reverse($methodsByClass);
        }

        $methods = [];

        foreach ($methodsByClass as $classMethods) {
            $methods = array_merge($methods, $classMethods);
        }

        return $methods;
    }

private function buildDataProviderTestSuite(string $methodName, string $className, array $data, bool $runTestInSeparateProcess, ?bool $preserveGlobalState, array $backupSettings, array $groups): DataProviderTestSuite
    {
        $dataProviderTestSuite = DataProviderTestSuite::empty(
            $className . '::' . $methodName,
        );

        $groups = array_merge(
            $groups,
            (new Groups)->groups($className, $methodName),
        );

        foreach ($data as $_dataName => $_data) {
            $_test = new $className($methodName);

            $_test->setData($_dataName, $_data->value());

            $this->configureTestCase(
                $_test,
                $runTestInSeparateProcess,
                $preserveGlobalState,
                $backupSettings,
            );

            $dataProviderTestSuite->addTest($_test, $groups);
        }

        return $dataProviderTestSuite;
    }

public static function getContentHash(string $composerFileContents): string
    {
        $content = JsonFile::parseJson($composerFileContents, 'composer.json');

        $relevantKeys = [
            'name',
            'version',
            'require',
            'require-dev',
            'conflict',
            'replace',
            'provide',
            'minimum-stability',
            'prefer-stable',
            'repositories',
            'extra',
        ];

        $relevantContent = [];

        foreach (array_intersect($relevantKeys, array_keys($content)) as $key) {
            $relevantContent[$key] = $content[$key];
        }
        if (isset($content['config']['platform'])) {
            $relevantContent['config']['platform'] = $content['config']['platform'];
        }

        ksort($relevantContent);

        return hash('md5', JsonFile::encode($relevantContent, 0));
    }

public function resolveType(MutatingScope $scope, Expr $expr): Type
	{
		$expressionType = $scope->getType($expr->expr);
		if (
			$scope->isInTrait()
			&& TypeUtils::findThisType($expressionType) !== null
		) {
			return new BooleanType();
		}
		if ($expressionType instanceof NeverType) {
			return new ConstantBooleanType(false);
		}

		$uncertainty = false;

		if ($expr->class instanceof Name) {
			$unresolvedClassName = $expr->class->toString();
			if (
				strtolower($unresolvedClassName) === 'static'
				&& $scope->isInClass()
			) {
				$classType = new StaticType($scope->getClassReflection());
			} else {
				$className = $scope->resolveName($expr->class);
				$classType = new ObjectType($className);
			}
		} else {
			$result = $scope->getType($expr->class)->toObjectTypeForInstanceofCheck();
			$classType = $result->type;
			$uncertainty = $result->uncertainty;
		}

		if ($classType->isSuperTypeOf(new MixedType())->yes()) {
			return new BooleanType();
		}

		$isSuperType = $classType->isSuperTypeOf($expressionType);

		if ($isSuperType->no()) {
			return new ConstantBooleanType(false);
		} elseif ($isSuperType->yes() && !$uncertainty) {
			return new ConstantBooleanType(true);
		}

		return new BooleanType();
	}

private function isReadonlyPropertyFetch(PropertyFetch $expr, bool $allowOnlyOnThis): bool
	{
		if (!$this->phpVersion->supportsReadOnlyProperties()) {
			return false;
		}

		while ($expr instanceof PropertyFetch) {
			if ($expr->var instanceof Variable) {
				if (
					$allowOnlyOnThis
					&& (
						! $expr->name instanceof Node\Identifier
						|| !is_string($expr->var->name)
						|| $expr->var->name !== 'this'
					)
				) {
					return false;
				}
			} elseif (!$expr->var instanceof PropertyFetch) {
				return false;
			}

			$propertyReflection = $this->propertyReflectionFinder->findPropertyReflectionFromNode($expr, $this);
			if ($propertyReflection === null) {
				return false;
			}

			$nativePropertyReflection = $propertyReflection->getNativeReflection();
			if ($nativePropertyReflection === null || !$nativePropertyReflection->isReadOnly()) {
				return false;
			}

			$expr = $expr->var;
		}

		return true;
	}

private function createProcessPromise(
	bool $useFork,
	LoopInterface $loop,
	TcpServer $server,
	string $mainScript,
	?string $projectConfigFile,
	InputInterface $input,
	int $serverPort,
	InceptionResult $inceptionResult,
): ProcessPromise
{
	if ($useFork) {
		try {
			[$inceptionFiles, $isOnlyFiles] = $inceptionResult->getFiles();
		} catch (PathNotFoundException | InceptionNotSuccessfulException) {
			throw new ShouldNotHappenException();
		}

		return new ForkedProcessPromise(
			$loop,
			$this->fixerWorkerRunner,
			$server,
			$inceptionResult->getErrorOutput(),
			$inceptionFiles,
			$isOnlyFiles,
			$inceptionResult->getProjectConfigArray(),
			$projectConfigFile,
			$serverPort,
			$input,
		);
	}

	return new SpawnedProcessPromise($loop, ProcessHelper::getWorkerCommand(
		$mainScript,
		'fixer:worker',
		$projectConfigFile,
		[
			'--server-port',
			(string) $serverPort,
		],
		$input,
	));
}

public function getProjectStubFiles(): array
	{
		if ($this->cachedProjectFiles !== null) {
			return $this->cachedProjectFiles;
		}

		$phpstanStubsDirectory = $this->fileHelper->normalizePath(dirname(dirname(__DIR__)) . '/stubs');

		$filteredStubFiles = $this->getStubFiles();
		$filteredStubFiles = array_filter(
			$filteredStubFiles,
			static fn (string $file): bool => !str_starts_with($file, $phpstanStubsDirectory),
		);
		foreach ($this->composerAutoloaderProjectPaths as $composerAutoloaderProjectPath) {
			$composerConfig = ComposerHelper::getComposerConfig($composerAutoloaderProjectPath);
			if ($composerConfig === null) {
				continue;
			}

			$vendorDir = ComposerHelper::getVendorDirFromComposerConfig($composerAutoloaderProjectPath, $composerConfig);
			$vendorDir = $this->fileHelper->normalizePath($vendorDir);
			$filteredStubFiles = array_filter(
				$filteredStubFiles,
				static fn (string $file): bool => !str_contains($file, $vendorDir),
			);
		}

		return $this->cachedProjectFiles = array_values($filteredStubFiles);
	}

public function run(): PromiseInterface
	{
		$tmpStdOutResource = tmpfile();
		if ($tmpStdOutResource === false) {
			throw new ShouldNotHappenException('Failed creating temp file for stdout.');
		}
		$tmpStdErrResource = tmpfile();
		if ($tmpStdErrResource === false) {
			throw new ShouldNotHappenException('Failed creating temp file for stderr.');
		}

		$this->process = new Process($this->command, fds: [
			1 => $tmpStdOutResource,
			2 => $tmpStdErrResource,
		]);
		$this->process->start($this->loop);

		$this->process->on('exit', function ($exitCode) use ($tmpStdOutResource, $tmpStdErrResource): void {
			if ($this->canceled) {
				fclose($tmpStdOutResource);
				fclose($tmpStdErrResource);
				return;
			}
			rewind($tmpStdOutResource);
			$stdOut = stream_get_contents($tmpStdOutResource);
			fclose($tmpStdOutResource);

			rewind($tmpStdErrResource);
			$stdErr = stream_get_contents($tmpStdErrResource);
			fclose($tmpStdErrResource);

			if ($exitCode === null) {
				$this->deferred->reject(new ProcessCrashedException($stdOut . $stdErr));
				return;
			}

			if ($exitCode === 0) {
				$this->deferred->resolve($stdOut);
				return;
			}

			$this->deferred->reject(new ProcessCrashedException($stdOut . $stdErr));
		});

		return $this->deferred->promise();
	}

public function processNode(Node $node, Scope $scope): array
	{
		$messages = [];
		foreach ($node->parts as $part) {
			if ($part instanceof Node\InterpolatedStringPart) {
				continue;
			}

			$typeResult = $this->ruleLevelHelper->findTypeToCheck(
				$scope,
				$part,
				'',
				static fn (Type $type): bool => !$type->toString() instanceof ErrorType,
			);
			$partType = $typeResult->getType();
			if ($partType instanceof ErrorType) {
				continue;
			}

			$stringPartType = $partType->toString();
			if (!$stringPartType instanceof ErrorType) {
				continue;
			}
			$messages[] = RuleErrorBuilder::message(sprintf(
				'Part %s (%s) of encapsed string cannot be cast to string.',
				$this->exprPrinter->printExpr($part),
				$partType->describe(VerbosityLevel::value()),
			))->identifier('encapsedStringPart.nonString')->line($part->getStartLine())->build();
		}

		return $messages;
	}

public function processNode(Node $node, Scope $scope): array
	{
		$method = $node->getMethodReflection();
		$originalNode = $node->getOriginalNode();
		if (!$method->isConstructor() || $originalNode->stmts === null) {
			return [];
		}

		if (count($originalNode->params) === 0) {
			return [];
		}
		if ($node->getClassReflection()->isAttributeClass()) {
			return [];
		}

		foreach ($node->getClassReflection()->getInterfaces() as $interface) {
			if ($interface->hasConstructor()) {
				return [];
			}
		}

		$message = sprintf(
			'Constructor of class %s has an unused parameter $%%s.',
			SprintfHelper::escapeFormatString($node->getClassReflection()->getDisplayName()),
		);
		if ($node->getClassReflection()->isAnonymous()) {
			$message = 'Constructor of an anonymous class has an unused parameter $%s.';
		}

		return $this->check->getUnusedParameters(
			$scope,
			array_map(static function (Param $parameter): Variable {
				if (!$parameter->var instanceof Variable) {
					throw new ShouldNotHappenException();
				}
				return $parameter->var;
			}, array_values(array_filter($originalNode->params, static fn (Param $parameter): bool => $parameter->flags === 0))),
			$originalNode->stmts,
			$message,
			'constructor.unusedParameter',
		);
	}

public function processNode(Node $node, Scope $scope): array
	{
		$pureKeys = $this->purityResolver->getPureCallableKeys($node);

		$methods = [];
		foreach ($node->get(MethodWithoutImpurePointsCollector::class) as $collected) {
			foreach ($collected as [$className, $methodName, $classDisplayName]) {
				if (!isset($pureKeys[PossiblyPureCallTransitivePurityResolver::methodKey($className, $methodName)])) {
					continue;
				}

				$methods[strtolower($className)][strtolower($methodName)] = $classDisplayName . '::' . $methodName;
			}
		}

		$errors = [];
		foreach ($node->get(PossiblyPureStaticCallCollector::class) as $filePath => $data) {
			foreach ($data as [$className, $method, $line]) {
				$lowerClassName = strtolower($className);

				if (!array_key_exists($lowerClassName, $methods)) {
					continue;
				}

				$lowerMethod = strtolower($method);
				if (!array_key_exists($lowerMethod, $methods[$lowerClassName])) {
					continue;
				}

				$originalMethodName = $methods[$lowerClassName][$lowerMethod];

				$errors[] = RuleErrorBuilder::message(sprintf(
					'Call to %s() on a separate line has no effect.',
					$originalMethodName,
				))->file($filePath)
					->line($line)
					->identifier('staticMethod.resultUnused')
					->build();
			}
		}

		return $errors;
	}

public function processNode(Node $node, Scope $scope): array
	{
		$statementResult = $node->getStatementResult();
		$functionReflection = $node->getFunctionReflection();

		if ($functionReflection->getThrowType() === null || !$functionReflection->getThrowType()->isVoid()->yes()) {
			return [];
		}

		$errors = [];
		foreach ($statementResult->getThrowPoints() as $throwPoint) {
			if (!$throwPoint->isExplicit()) {
				continue;
			}

			foreach (TypeUtils::flattenTypes($throwPoint->getType()) as $throwPointType) {
				$isCheckedException = TrinaryLogic::createFromBoolean($this->missingCheckedExceptionInThrows)->lazyAnd(
					$throwPointType->getObjectClassNames(),
					fn (string $objectClassName) => TrinaryLogic::createFromBoolean($this->exceptionTypeResolver->isCheckedException($objectClassName, $throwPoint->getScope())),
				);
				if ($isCheckedException->yes()) {
					continue;
				}

				$errors[] = RuleErrorBuilder::message(sprintf(
					'Function %s() throws exception %s but the PHPDoc contains @throws void.',
					$functionReflection->getName(),
					$throwPointType->describe(VerbosityLevel::typeOnly()),
				))
					->line($throwPoint->getNode()->getStartLine())
					->identifier('throws.void')
					->build();
			}
		}

		return $errors;
	}

private function callReturnsByReference(Expr $expr, Scope $scope): bool
	{
		if ($expr instanceof Node\Expr\MethodCall) {
			if (!$expr->name instanceof Node\Identifier) {
				return false;
			}
			$calledOnType = $scope->getType($expr->var);
			$methodReflection = $scope->getMethodReflection($calledOnType, $expr->name->name);
			if ($methodReflection === null) {
				return false;
			}
			return $methodReflection->returnsByReference()->yes();
		}

		if ($expr instanceof Node\Expr\StaticCall) {
			if (!$expr->name instanceof Node\Identifier) {
				return false;
			}
			if ($expr->class instanceof Node\Name) {
				$calledOnType = $scope->resolveTypeByName($expr->class);
			} else {
				$calledOnType = $scope->getType($expr->class);
			}
			$methodReflection = $scope->getMethodReflection($calledOnType, $expr->name->name);
			if ($methodReflection === null) {
				return false;
			}
			return $methodReflection->returnsByReference()->yes();
		}

		if ($expr instanceof Node\Expr\FuncCall) {
			if ($expr->name instanceof Node\Name) {
				if ($this->reflectionProvider->hasFunction($expr->name, $scope)) {
					$functionReflection = $this->reflectionProvider->getFunction($expr->name, $scope);
					return $functionReflection->returnsByReference()->yes();
				}
			}
		}

		return false;
	}

public function processNode(Node $node, Scope $scope): array
	{
		$function = $node->getFunctionReflection();
		$errors = [];
		foreach ($node->getOriginalNode()->getParams() as $paramI => $param) {
			if ($param->default === null) {
				continue;
			}
			if (
				$param->var instanceof Node\Expr\Error
				|| !is_string($param->var->name)
			) {
				throw new ShouldNotHappenException();
			}

			$defaultValueType = $scope->getType($param->default);
			$parameterType = $function->getParameters()[$paramI]->getType();
			$parameterType = TemplateTypeHelper::resolveToBounds($parameterType);

			$accepts = $parameterType->accepts($defaultValueType, true);
			if ($accepts->yes()) {
				continue;
			}

			$verbosityLevel = VerbosityLevel::getRecommendedLevelByType($parameterType, $defaultValueType);

			$errors[] = RuleErrorBuilder::message(sprintf(
				'Default value of the parameter #%d $%s (%s) of function %s() is incompatible with type %s.',
				$paramI + 1,
				$param->var->name,
				$defaultValueType->describe($verbosityLevel),
				$function->getName(),
				$parameterType->describe($verbosityLevel),
			))
				->line($param->getStartLine())
				->identifier('parameter.defaultValue')
				->acceptsReasonsTip($accepts->reasons)
				->build();
		}

		return $errors;
	}

public function setOffsetValueType(?Type $offsetType, Type $valueType, bool $unionValues = true): Type
	{
		if ($this->isOffsetAccessible()->no()) {
			return new ErrorType();
		}

		if ($this->isInstanceOf(ArrayAccess::class)->yes()) {
			$acceptedValueType = new NeverType();
			$acceptedOffsetType = RecursionGuard::run($this, function () use (&$acceptedValueType): Type {
				$parameters = $this->getMethod('offsetSet', new OutOfClassScope())->getOnlyVariant()->getParameters();
				if (count($parameters) < 2) {
					throw new ShouldNotHappenException(sprintf(
						'Method %s::%s() has less than 2 parameters.',
						$this->className,
						'offsetSet',
					));
				}

				$offsetParameter = $parameters[0];
				$acceptedValueType = $parameters[1]->getType();

				return $offsetParameter->getType();
			});

			if ($offsetType === null) {
				$offsetType = new NullType();
			}

			if (
				(!$offsetType instanceof MixedType && !$acceptedOffsetType->isSuperTypeOf($offsetType)->yes())
				|| (!$valueType instanceof MixedType && !$acceptedValueType->isSuperTypeOf($valueType)->yes())
			) {
				return new ErrorType();
			}
		}

		// in the future we may return intersection of $this and OffsetAccessibleType()
		return $this;
	}

public function getTypeFromFunctionCall(FunctionReflection $functionReflection, FuncCall $functionCall, Scope $scope): Type
	{
		$args = $functionCall->getArgs();
		$returnType = ParametersAcceptorSelector::selectFromArgs(
			$scope,
			$args,
			$functionReflection->getVariants(),
		)->getReturnType();
		$positionEncodingParam = $this->encodingPositionMap[$functionReflection->getName()];

		if (count($args) < $positionEncodingParam) {
			return TypeCombinator::remove($returnType, new BooleanType());
		}

		$strings = $scope->getType($args[$positionEncodingParam - 1]->value)->getConstantStrings();
		$results = array_unique(array_map(fn (ConstantStringType $encoding): bool => $this->isSupportedEncoding($encoding->getValue()), $strings));

		if ($returnType->equals(new UnionType([new StringType(), new BooleanType()]))) {
			return count($results) === 1 ? new ConstantBooleanType($results[0]) : new BooleanType();
		}

		if (count($results) === 1) {
			$invalidEncodingReturn = new ConstantBooleanType(false);
			if ($this->phpVersion->throwsOnInvalidMbStringEncoding()) {
				$invalidEncodingReturn = new NeverType();
			}

			return $results[0]
				? TypeCombinator::remove($returnType, new ConstantBooleanType(false))
				: $invalidEncodingReturn;
		}

		return $returnType;
	}

public function inferTemplateTypes(Type $receivedType): TemplateTypeMap
	{
		if ($receivedType instanceof IterableType) {
			$receivedType = $receivedType->toArrayOrTraversable();
		}

		$types = TemplateTypeMap::createEmpty();
		if ($receivedType instanceof UnionType) {
			$myTypes = [];
			$remainingReceivedTypes = [];
			foreach ($receivedType->getTypes() as $receivedInnerType) {
				foreach ($this->types as $type) {
					if ($type->isSuperTypeOf($receivedInnerType)->yes()) {
						$types = $types->union($type->inferTemplateTypes($receivedInnerType));
						continue 2;
					}
					$myTypes[] = $type;
				}
				$remainingReceivedTypes[] = $receivedInnerType;
			}
			if (count($remainingReceivedTypes) === 0) {
				return $types;
			}
			$receivedType = TypeCombinator::union(...$remainingReceivedTypes);
		} else {
			$myTypes = $this->types;
		}

		foreach ($myTypes as $type) {
			if ($type instanceof TemplateType || ($type instanceof GenericClassStringType && $type->getGenericType() instanceof TemplateType)) {
				continue;
			}
			$types = $types->union($type->inferTemplateTypes($receivedType));
		}

		if (!$types->isEmpty()) {
			return $types;
		}

		foreach ($myTypes as $type) {
			$types = $types->union($type->inferTemplateTypes($receivedType));
		}

		return $types;
	}

protected function execute(InputInterface $input, OutputInterface $output): int
    {
        $io = new SymfonyStyle($input, $output);

        $transportNames = $this->transportNames;
        // do we want to set up only one transport?
        if ($transport = $input->getArgument('transport')) {
            if (!$this->transportLocator->has($transport)) {
                throw new \RuntimeException(\sprintf('The "%s" transport does not exist.', $transport));
            }
            $transportNames = [$transport];
        }

        foreach ($transportNames as $id => $transportName) {
            $transport = $this->transportLocator->get($transportName);
            if (!$transport instanceof SetupableTransportInterface) {
                $io->note(\sprintf('The "%s" transport does not support setup.', $transportName));
                continue;
            }

            try {
                $transport->setup();
                $io->success(\sprintf('The "%s" transport was set up successfully.', $transportName));
            } catch (\Exception $e) {
                throw new \RuntimeException(\sprintf('An error occurred while setting up the "%s" transport: ', $transportName).$e->getMessage(), 0, $e);
            }
        }

        return 0;
    }

public function load(mixed $file, ?string $type = null): RouteCollection
    {
        $path = $this->locator->locate($file);

        if (!stream_is_local($path)) {
            throw new \InvalidArgumentException(\sprintf('This is not a local file "%s".', $path));
        }

        if (!file_exists($path)) {
            throw new \InvalidArgumentException(\sprintf('File "%s" not found.', $path));
        }

        $this->yamlParser ??= new YamlParser();

        try {
            $parsedConfig = $this->yamlParser->parseFile($path, Yaml::PARSE_CONSTANT);
        } catch (ParseException $e) {
            throw new \InvalidArgumentException(\sprintf('The file "%s" does not contain valid YAML: ', $path).$e->getMessage(), 0, $e);
        }

        $collection = new RouteCollection();
        $collection->addResource(new FileResource($path));

        // empty file
        if (null === $parsedConfig) {
            return $collection;
        }

        // not an array
        if (!\is_array($parsedConfig)) {
            throw new \InvalidArgumentException(\sprintf('The file "%s" must contain a YAML array.', $path));
        }

        $this->loadContent($collection, $parsedConfig, $path, $file);

        return $collection;
    }

public function split(string $delimiter, ?int $limit = null, ?int $flags = null): array
    {
        if (1 > $limit ??= 2147483647) {
            throw new InvalidArgumentException('Split limit must be a positive integer.');
        }

        if ('' === $delimiter) {
            throw new InvalidArgumentException('Split delimiter is empty.');
        }

        if (null !== $flags) {
            return parent::split($delimiter.'u', $limit, $flags);
        }

        normalizer_is_normalized($delimiter) ?: $delimiter = normalizer_normalize($delimiter);

        if (false === $delimiter) {
            throw new InvalidArgumentException('Split delimiter is not a valid UTF-8 string.');
        }

        $str = clone $this;
        $tail = $this->string;
        $chunks = [];
        $indexOf = $this->ignoreCase ? 'grapheme_stripos' : 'grapheme_strpos';

        while (1 < $limit && false !== $i = $indexOf($tail, $delimiter)) {
            $str->string = grapheme_substr($tail, 0, $i);
            $chunks[] = clone $str;
            $tail = substr($tail, \strlen($str->string) + \strlen($delimiter));
            --$limit;
        }

        $str->string = $tail;
        $chunks[] = clone $str;

        return $chunks;
    }

private function findSimilar(string $package): array
    {
        try {
            if (null === $this->repos) {
                throw new \LogicException('findSimilar was called before $this->repos was initialized');
            }
            $results = $this->repos->search($package);
        } catch (\Throwable $e) {
            if ($e instanceof \LogicException) {
                throw $e;
            }

            // ignore search errors
            return [];
        }
        $similarPackages = [];

        $installedRepo = $this->requireComposer()->getRepositoryManager()->getLocalRepository();

        foreach ($results as $result) {
            if (null !== $installedRepo->findPackage($result['name'], '*')) {
                // Ignore installed package
                continue;
            }
            $similarPackages[$result['name']] = levenshtein($package, $result['name']);
        }
        asort($similarPackages);

        return array_keys(array_slice($similarPackages, 0, 5));
    }

public function getComposer(bool $required = true, ?bool $disablePlugins = null, ?bool $disableScripts = null): ?Composer
    {
        if (null === $disablePlugins) {
            $disablePlugins = $this->disablePluginsByDefault;
        }
        if (null === $disableScripts) {
            $disableScripts = $this->disableScriptsByDefault;
        }

        if (null === $this->composer) {
            try {
                $this->composer = Factory::create(Platform::isInputCompletionProcess() ? new NullIO() : $this->io, null, $disablePlugins, $disableScripts);
            } catch (\InvalidArgumentException $e) {
                if ($required) {
                    $this->io->writeError($e->getMessage());
                    if ($this->areExceptionsCaught()) {
                        exit(1);
                    }
                    throw $e;
                }
            } catch (JsonValidationException $e) {
                if ($required) {
                    throw $e;
                }
            } catch (RuntimeException $e) {
                if ($required) {
                    throw $e;
                }
            }
        }

        return $this->composer;
    }

private function runFilterListFilter(Pool $pool, Request $request): Pool
    {
        if (null === $this->filterListPoolFilter) {
            return $pool;
        }

        $this->io->debug('Running filter list pool filter.');

        $before = microtime(true);
        $total = \count($pool->getPackages());

        $pool = $this->filterListPoolFilter->filter($pool, $request);

        $filtered = $total - \count($pool->getPackages());

        if (0 === $filtered) {
            return $pool;
        }

        $this->io->write(sprintf('Filter list pool filter completed in %.3f seconds', microtime(true) - $before), true, IOInterface::VERY_VERBOSE);
        $this->io->write(sprintf(
            '<info>Found %s package versions referenced in your dependency graph. %s (%d%%) were filtered away by dependency policies.</info>',
            number_format($total),
            number_format($filtered),
            round(100 / $total * $filtered)
        ), true, IOInterface::VERY_VERBOSE);

        return $pool;
    }

